ll fact[N], invfact[N];

ll powmod(ll a, ll b) {

  ll res = 1;

  while (b) {

    if (b & 1) res = res * a % mod;

    a = a * a % mod;

    b >>= 1;

  }

  return res;

}

ll comb(int n, int m) {

  return fact[n] * invfact[m] % mod * invfact[n - m] % mod;

}

