  scanf("%d%d", &n, &k);

  for (int i = 1; i <= n; i++) scanf("%lld", &a[i]);

  sort(a + 1, a + n + 1);

  fact[0] = 1;

  for (int i = 1; i <= n; i++) fact[i] = fact[i - 1] * i % mod;

  invfact[n] = powmod(fact[n], mod - 2);

